import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";

export default function PaymentSystem() {
  const today = new Date().toISOString().split("T")[0];

  const [showForm, setShowForm] = useState(false);
  const [payments, setPayments] = useState([]);

  const [form, setForm] = useState({
    title: "",
    paymentFor: "MATERIAL",

    materialName: "",
    projectName: "",

    workerName: "",
    workType: "",

    description: "",
    amount: "",
    paidAmount: "",

    date: today,
    notes: ""
  });

  useEffect(() => {
    fetch("http://localhost:5000/payments")
      .then((res) => res.json())
      .then((data) => setPayments(data));
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const getTotal = () => Number(form.amount || 0);

  const getRemaining = (total, paid) =>
    Number(total) - Number(paid || 0);

  const getStatus = (total, paid) => {
    if (!paid || Number(paid) === 0) return "PENDING 🔴";
    if (Number(paid) >= Number(total)) return "PAID ✅";
    return "PARTIAL 🟡";
  };

  const savePayment = async (e) => {
    e.preventDefault();

    const total = getTotal();
    const paid = Number(form.paidAmount || 0);
    const remaining = getRemaining(total, paid);

    const payload = {
      ...form,
      totalAmount: total,
      paidAmount: paid,
      remainingAmount: remaining
    };

    const res = await fetch("http://localhost:5000/payments", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });

    const data = await res.json();

    setPayments([...payments, { ...payload, id: data.id }]);
    setShowForm(false);
  };

  const deletePayment = (index) => {
    setPayments(payments.filter((_, i) => i !== index));
  };

  return (
    <div className="flex bg-gray-100 min-h-screen">
      <Sidebar />

      <div className="flex-1 p-8">

        <div className="flex justify-between mb-6">
          <h1 className="text-2xl font-bold">Payments Management</h1>

          <button
            onClick={() => setShowForm(true)}
            className="bg-blue-600 text-white px-4 py-2 rounded"
          >
            + Add Payment
          </button>
        </div>

        {/* FORM */}
        {showForm && (
          <form
            onSubmit={savePayment}
            className="bg-white p-6 rounded shadow grid grid-cols-2 gap-4 mb-6"
          >
            {/* TITLE */}
            <div>
              <label className="block mb-1 font-medium">Title</label>
              <input
                name="title"
                onChange={handleChange}
                className="border p-2 w-full"
              />
            </div>

            {/* PAYMENT FOR */}
            <div>
              <label className="block mb-1 font-medium">Payment For</label>
              <select
                name="paymentFor"
                onChange={handleChange}
                className="border p-2 w-full"
              >
                <option value="MATERIAL">Material</option>
                <option value="WORKER">Worker</option>
                <option value="OTHER">Other</option>
              </select>
            </div>

            {/* AMOUNT */}
            <div>
              <label className="block mb-1 font-medium">Total Amount</label>
              <input
                name="amount"
                onChange={handleChange}
                className="border p-2 w-full"
              />
            </div>

            {/* PAID AMOUNT */}
            <div>
              <label className="block mb-1 font-medium">Paid Amount</label>
              <input
                name="paidAmount"
                onChange={handleChange}
                className="border p-2 w-full"
              />
            </div>

            {/* DATE */}
            <div>
              <label className="block mb-1 font-medium">Date</label>
              <input
                type="date"
                name="date"
                value={form.date}
                onChange={handleChange}
                className="border p-2 w-full"
              />
            </div>

            {/* NOTES */}
            <div className="col-span-2">
              <label className="block mb-1 font-medium">Notes</label>
              <textarea
                name="notes"
                onChange={handleChange}
                className="border p-2 w-full"
              />
            </div>

            <button className="bg-green-600 text-white p-2 rounded">
              Save
            </button>

            <button
              type="button"
              onClick={() => setShowForm(false)}
              className="border p-2 rounded"
            >
              Cancel
            </button>
          </form>
        )}

        {/* TABLE */}
        <div className="bg-white rounded shadow">
          <table className="w-full">
            <thead className="bg-gray-200">
              <tr>
                <th className="p-2">Title</th>
                <th>Total</th>
                <th>Paid</th>
                <th>Remaining</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>

            <tbody>
              {payments.map((p, i) => (
                <tr key={i} className="border-t text-center">
                  <td>{p.title}</td>
                  <td>{p.totalAmount}</td>
                  <td>{p.paidAmount}</td>
                  <td>{p.remainingAmount}</td>
                  <td>{getStatus(p.totalAmount, p.paidAmount)}</td>

                  <td>
                    <button
                      onClick={() => deletePayment(i)}
                      className="text-red-600"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

      </div>
    </div>
  );
}
